class Solution {
public:
    vector<int> smallestTrimmedNumbers(vector<string>& nums, vector<vector<int>>& queries) {
        vector<int> answer;
        for (auto& query : queries) {
            int k = query[0], trim = query[1];
            vector<string> trimmed;
            for (string& num : nums) {
                trimmed.push_back(num.substr(num.length() - trim));
            }
            sort(trimmed.begin(), trimmed.end());
            answer.push_back(distance(trimmed.begin(), lower_bound(trimmed.begin(), trimmed.end(), string(k - 1, '9') + string(trim.length(), '0')));
        }
        return answer;
    }
};
